using Microsoft.VisualStudio.TestTools.UnitTesting;
using Warehouse;

namespace Warehouse.Tests;

[TestClass]
public class InventoryTrackerTests
{
    private InventoryTracker _tracker = null!;

    [TestInitialize]
    public void Setup()
    {
        _tracker = new InventoryTracker(reorderThreshold: 10);
    }

    // ---------------------------------------------------------------
    // Constructor
    // ---------------------------------------------------------------

    [TestMethod]
    public void Constructor_DefaultThreshold_DoesNotThrow()
    {
        var tracker = new InventoryTracker();
        Assert.AreEqual(0, tracker.GetStockLevel("ANY-SKU"));
    }

    [TestMethod]
    public void Constructor_ExplicitThreshold_IsUsed()
    {
        var tracker = new InventoryTracker(reorderThreshold: 5);
        tracker.AddStock("SKU-1", 5);

        Assert.IsTrue(tracker.NeedsReorder("SKU-1"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void Constructor_NegativeThreshold_Throws()
    {
        _ = new InventoryTracker(reorderThreshold: -1);
    }

    // ---------------------------------------------------------------
    // GetStockLevel
    // ---------------------------------------------------------------

    [TestMethod]
    public void GetStockLevel_UnknownSku_ReturnsZero()
    {
        Assert.AreEqual(0, _tracker.GetStockLevel("UNKNOWN"));
    }

    [TestMethod]
    public void GetStockLevel_AfterAdd_ReturnsCorrectLevel()
    {
        _tracker.AddStock("SKU-A", 25);
        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void GetStockLevel_IsCaseInsensitive()
    {
        _tracker.AddStock("sku-a", 10);
        Assert.AreEqual(10, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GetStockLevel_NullSku_Throws()
    {
        _tracker.GetStockLevel(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GetStockLevel_EmptySku_Throws()
    {
        _tracker.GetStockLevel("   ");
    }

    // ---------------------------------------------------------------
    // AddStock
    // ---------------------------------------------------------------

    [TestMethod]
    public void AddStock_NewSku_SetsLevel()
    {
        _tracker.AddStock("SKU-NEW", 50);
        Assert.AreEqual(50, _tracker.GetStockLevel("SKU-NEW"));
    }

    [TestMethod]
    public void AddStock_ExistingSku_Accumulates()
    {
        _tracker.AddStock("SKU-A", 10);
        _tracker.AddStock("SKU-A", 15);
        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddStock_ZeroQuantity_Throws()
    {
        _tracker.AddStock("SKU-A", 0);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddStock_NegativeQuantity_Throws()
    {
        _tracker.AddStock("SKU-A", -5);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddStock_NullSku_Throws()
    {
        _tracker.AddStock(null!, 1);
    }

    // ---------------------------------------------------------------
    // RemoveStock
    // ---------------------------------------------------------------

    [TestMethod]
    public void RemoveStock_SufficientStock_ReducesLevel()
    {
        _tracker.AddStock("SKU-A", 20);
        _tracker.RemoveStock("SKU-A", 5);
        Assert.AreEqual(15, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void RemoveStock_EntireStock_LeavesZero()
    {
        _tracker.AddStock("SKU-A", 10);
        _tracker.RemoveStock("SKU-A", 10);
        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void RemoveStock_InsufficientStock_Throws()
    {
        _tracker.AddStock("SKU-A", 5);
        _tracker.RemoveStock("SKU-A", 10);
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void RemoveStock_UnknownSku_Throws()
    {
        _tracker.RemoveStock("UNKNOWN", 1);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void RemoveStock_ZeroQuantity_Throws()
    {
        _tracker.RemoveStock("SKU-A", 0);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void RemoveStock_NegativeQuantity_Throws()
    {
        _tracker.RemoveStock("SKU-A", -3);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void RemoveStock_NullSku_Throws()
    {
        _tracker.RemoveStock(null!, 1);
    }

    // ---------------------------------------------------------------
    // NeedsReorder
    // ---------------------------------------------------------------

    [TestMethod]
    public void NeedsReorder_StockBelowThreshold_ReturnsTrue()
    {
        _tracker.AddStock("SKU-A", 5);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void NeedsReorder_StockAtThreshold_ReturnsTrue()
    {
        _tracker.AddStock("SKU-A", 10);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void NeedsReorder_StockAboveThreshold_ReturnsFalse()
    {
        _tracker.AddStock("SKU-A", 11);
        Assert.IsFalse(_tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void NeedsReorder_UnknownSku_ReturnsTrue()
    {
        Assert.IsTrue(_tracker.NeedsReorder("UNKNOWN"));
    }

    [TestMethod]
    public void NeedsReorder_AfterRemovalDropsBelowThreshold_ReturnsTrue()
    {
        _tracker.AddStock("SKU-A", 15);
        Assert.IsFalse(_tracker.NeedsReorder("SKU-A"));

        _tracker.RemoveStock("SKU-A", 10);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void NeedsReorder_NullSku_Throws()
    {
        _tracker.NeedsReorder(null!);
    }

    // ---------------------------------------------------------------
    // Transfer
    // ---------------------------------------------------------------

    [TestMethod]
    public void Transfer_ValidTransfer_MovesStock()
    {
        var warehouseA = new InventoryTracker();
        var warehouseB = new InventoryTracker();

        warehouseA.AddStock("SKU-X", 30);
        InventoryTracker.Transfer(warehouseA, warehouseB, "SKU-X", 10);

